  export async function getDocFromFirebase(db){

    const postList = [];
    async function getValsFromFirestore(ID){
        const docRef = doc(db, "blogPosts", ID);
        try{        
          const doc = await getDoc(docRef);
          return(doc.data())
        } catch (e) {
          console.log("Error getting cached document:", e);
        }
      }

    try {
      const querySnapshot = await getDocs(collection(db, "blogPosts"));
      querySnapshot.forEach((doc) => {
          let post = {};  
          getValsFromFirestore(doc.id).then((val) => post[doc.id] = val);
          console.log(post);
          postList.push(post);
        }
        );
    }
    catch(e){
      console.log("Error", e);
    }
    finally{
        console.log(postList);
    }
  }