import React from 'react';
import {Link} from "react-router-dom";

//txt - Title; Text


class BlogPost extends React.Component {

    constructor(props) {
        super(props);
    }

    render(){
        return(
            <header className="App-header">
                {this.props.title}
                <div>
                    {this.props.body}
                </div>
            </header>
        );
    }
}

class BlogPostPreview extends React.Component {

    constructor(props) {
        super(props);
    }

    render(){
        return(
            <div>
                <Link to={{pathname: `/blog/${this.props.link}`}} className="App-link">
                    {this.props.title}!
                </Link>
                
            </div>
        );
    }
}





export {BlogPost, BlogPostPreview};